import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, String label) {
        int size = (int) n;
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            adj.add(new ArrayList<>());
        }
        for (int i = 0; i < edges.length; i++) {
            int u = (int) edges[i][0];
            int v = (int) edges[i][1];
            adj.get(u).add(v);
            adj.get(v).add(u);
        }
        long maxLen = 1;
        boolean[] visited = new boolean[size];
        long[] max = new long[1];
        max[0] = 1;
        for (int start = 0; start < size; start++) {
            visited[start] = true;
            List<Integer> path = new ArrayList<>();
            path.add(start);
            backtrack(start, adj, visited, label, path, max);
            visited[start] = false;
        }
        return max[0];
    }

    private static void backtrack(int current, List<List<Integer>> adj, boolean[] visited, String label, List<Integer> path, long[] max) {
        int l = path.size();
        boolean isPalindrome = true;
        for (int i = 0; i < l / 2; i++) {
            if (label.charAt(path.get(i)) != label.charAt(path.get(l - 1 - i))) {
                isPalindrome = false;
                break;
            }
        }
        if (isPalindrome) {
            if (l > max[0]) {
                max[0] = l;
            }
        }
        for (int neighbor : adj.get(current)) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                path.add(neighbor);
                backtrack(neighbor, adj, visited, label, path, max);
                path.remove(path.size() - 1);
                visited[neighbor] = false;
            }
        }
    }
}
